CREATE OR REPLACE FUNCTION to_znumber (adc_amount bigint,ai_left integer ) RETURNS varchar AS $body$
DECLARE

  ldc_dec bigint;
  ldc_full bigint;
  ls_dec char(2);

BEGIN
  -- แปลงเป็น ตัวเลขเติม 0 ด้านหน้า ไม่เอาจุด
  ldc_dec := mod(adc_amount,1);
  if ldc_dec > 0 then
    ldc_full := adc_amount - ldc_dec;
    ls_dec := Rpad(substr(trim(both ldc_dec),2),2,'0');
  else
    ldc_full := adc_amount;
    ls_dec := '00';
  end if;
  return Lpad(trim(both ldc_full)||ls_dec,ai_left,'0');
end;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
